def _sort_palette(self, sort_palette):
    """
    Reorders the palette of a "P" mode image without altering its
    appearance, using one of the predefined :meth:`quantize`
    ``sort_palette`` methods.
    """
    if sort_palette not in ("rgb", "brightness"):
        raise ValueError("sort_palette must be 'rgb' or 'brightness'")

    num_colors = len(self.getcolors(maxcolors=256))
    rgb palette = self.getpalette()
    colors = [
        tuple(rgb_palette[i * 3 : i * 3 + 3]) for i in range(num_colors)
    ]

    if sort_palette == "brightness":

        def sort_key(i):
            r, g, b = colors[i]
            return 0.299 * r + 0.587 * g + 0.114 * b

    else:

        def sort_key(i):
            return colors[i]

    dest_map = sorted(range(num_colors), key=sort_key)
    return self.remap_palette(dest_map)

